using MutationTestingDemo.Models;
using MutationTestingDemo.Services;

namespace MutationTestingDemo.Tests.After;

public class DiscountServiceTests
{
    private readonly DiscountService _sut = new();

    [Fact]
    public void VipCustomer_ShouldGet15PercentDiscount()
    {
        var customer = new Customer { Name = "Mario Rossi", IsVip = true, LoyaltyYears = 1 };

        var result = _sut.CalculateDiscount(customer, 150m);

        // VIP 15% di 150 = 22.50
        Assert.Equal(22.50m, result);
    }

    [Fact]
    public void VipWithLargeOrder_ShouldGetCombinedDiscount()
    {
        var customer = new Customer { Name = "Mario Rossi", IsVip = true, LoyaltyYears = 1 };

        var result = _sut.CalculateDiscount(customer, 300m);

        // VIP 15% + ordine > 200 5% = 20% di 300 = 60
        Assert.Equal(60m, result);
    }

    [Fact]
    public void LargeOrder_NonVip_ShouldGet5PercentDiscount()
    {
        var customer = new Customer { Name = "Luigi Verdi", IsVip = false, LoyaltyYears = 0 };

        var result = _sut.CalculateDiscount(customer, 250m);

        // Solo ordine > 200: 5% di 250 = 12.50
        Assert.Equal(12.50m, result);
    }

    [Fact]
    public void LoyalCustomer_ShouldGetLoyaltyDiscount()
    {
        var customer = new Customer { Name = "Anna Bianchi", IsVip = false, LoyaltyYears = 5 };

        var result = _sut.CalculateDiscount(customer, 150m);

        Assert.Equal(15m, result);
    }

    [Fact]
    public void RegularCustomer_ShouldGetNoDiscount()
    {
        var customer = new Customer { Name = "Giulia Neri", IsVip = false, LoyaltyYears = 0 };

        var result = _sut.CalculateDiscount(customer, 100m);

        Assert.Equal(0m, result);
    }

    // --- Boundary tests ---

    [Fact]
    public void Boundary_ExactlyAt200_ShouldNotGetOrderDiscount()
    {
        var customer = new Customer { Name = "Marco Gialli", IsVip = false, LoyaltyYears = 0 };

        var result = _sut.CalculateDiscount(customer, 200m);

        Assert.Equal(0m, result);
    }

    [Fact]
    public void Boundary_JustAbove200_ShouldGetOrderDiscount()
    {
        var customer = new Customer { Name = "Marco Gialli", IsVip = false, LoyaltyYears = 0 };

        var result = _sut.CalculateDiscount(customer, 200.01m);

        Assert.Equal(200.01m * 0.05m, result);
    }

    [Fact]
    public void Boundary_Exactly3YearsLoyalty_ShouldGetDiscount()
    {
        var customer = new Customer { Name = "Sara Blu", IsVip = false, LoyaltyYears = 3 };

        var result = _sut.CalculateDiscount(customer, 100m);

        Assert.Equal(10m, result);
    }

    [Fact]
    public void Boundary_2YearsLoyalty_ShouldNotGetDiscount()
    {
        var customer = new Customer { Name = "Sara Blu", IsVip = false, LoyaltyYears = 2 };

        var result = _sut.CalculateDiscount(customer, 100m);

        Assert.Equal(0m, result);
    }

    [Fact]
    public void Cap_AllDiscountsCombined_ShouldNotExceed25Percent()
    {
        // VIP (15%) + ordine > 200 (5%) + fedelta' >= 3 (10%) = 30%, cappato a 25%
        var customer = new Customer { Name = "Top Customer", IsVip = true, LoyaltyYears = 5 };

        var result = _sut.CalculateDiscount(customer, 400m);

        // 25% di 400 = 100 (non 30% = 120)
        Assert.Equal(100m, result);
    }
}

using MutationTestingDemo.Exceptions;
using MutationTestingDemo.Models;
using MutationTestingDemo.Services;

namespace MutationTestingDemo.Tests.After;

public class OrderServiceTests
{
    private readonly OrderService _sut = new(new DiscountService(), new ShippingService());

    [Fact]
    public void VipOrder_ShouldCalculateCorrectTotals()
    {
        var order = new Order
        {
            Customer = new Customer { Name = "Mario Rossi", IsVip = true, LoyaltyYears = 1 },
            Items = new List<OrderItem>
            {
                new() { ProductName = "Tastiera meccanica", UnitPrice = 80m, Quantity = 2 },
                new() { ProductName = "Mouse wireless", UnitPrice = 40m, Quantity = 1 }
            }
        };

        var result = _sut.ProcessOrder(order);

        // Subtotale: 80*2 + 40*1 = 200 (multi-item killa Sum->Max)
        Assert.Equal(200m, result.Subtotal);
        // VIP 15% di 200 = 30
        Assert.Equal(30m, result.DiscountAmount);
        // VIP -> spedizione gratuita
        Assert.Equal(0m, result.ShippingCost);
        Assert.Equal(ShippingType.Free, result.ShippingType);
        // Totale: 200 - 30 + 0 = 170
        Assert.Equal(170m, result.Total);
        // Status confermato
        Assert.Equal(OrderStatus.Confirmed, result.Status);
    }

    [Fact]
    public void MultipleItems_ShouldSumCorrectly()
    {
        var order = new Order
        {
            Customer = new Customer { Name = "Luigi Verdi", IsVip = false, LoyaltyYears = 0 },
            Items = new List<OrderItem>
            {
                new() { ProductName = "Cavo USB-C", UnitPrice = 10m, Quantity = 3 },
                new() { ProductName = "Mouse wireless", UnitPrice = 40m, Quantity = 2 }
            }
        };

        var result = _sut.ProcessOrder(order);

        // Subtotale: 10*3 + 40*2 = 110 (Quantity > 1 killa * -> /)
        Assert.Equal(110m, result.Subtotal);
    }

    [Fact]
    public void NonVipSmallOrder_ShouldHaveStandardShipping()
    {
        var order = new Order
        {
            Customer = new Customer { Name = "Luigi Verdi", IsVip = false, LoyaltyYears = 0 },
            Items = new List<OrderItem>
            {
                new() { ProductName = "Cavo USB-C", UnitPrice = 10m, Quantity = 3 }
            }
        };

        var result = _sut.ProcessOrder(order);

        // Subtotale 30, nessuno sconto, Standard 5.00
        Assert.Equal(30m, result.Subtotal);
        Assert.Equal(0m, result.DiscountAmount);
        Assert.Equal(5.00m, result.ShippingCost);
        Assert.Equal(ShippingType.Standard, result.ShippingType);
        // Totale: 30 - 0 + 5 = 35 (killa +/- sulla spedizione)
        Assert.Equal(35m, result.Total);
        Assert.Equal(OrderStatus.Confirmed, result.Status);
    }

    [Fact]
    public void EmptyOrder_ShouldThrowWithMessage()
    {
        var order = new Order
        {
            Customer = new Customer { Name = "Giulia Neri" },
            Items = new List<OrderItem>()
        };

        var ex = Assert.Throws<InvalidOrderException>(() => _sut.ProcessOrder(order));
        Assert.Contains("almeno un prodotto", ex.Message);
    }

    [Fact]
    public void NullItems_ShouldThrow()
    {
        var order = new Order
        {
            Customer = new Customer { Name = "Giulia Neri" },
            Items = null!
        };

        Assert.Throws<InvalidOrderException>(() => _sut.ProcessOrder(order));
    }

    [Fact]
    public void MediumOrder_ShouldGetExpressShipping()
    {
        var order = new Order
        {
            Customer = new Customer { Name = "Paolo Viola", IsVip = false, LoyaltyYears = 0 },
            Items = new List<OrderItem>
            {
                new() { ProductName = "Tastiera meccanica", UnitPrice = 75m, Quantity = 2 }
            }
        };

        var result = _sut.ProcessOrder(order);

        Assert.Equal(150m, result.Subtotal);
        Assert.Equal(0m, result.DiscountAmount);
        Assert.Equal(7.50m, result.ShippingCost);
        Assert.Equal(ShippingType.Express, result.ShippingType);
        Assert.Equal(157.50m, result.Total);
        Assert.Equal(OrderStatus.Confirmed, result.Status);
    }
}

